# /// script
# requires-python = ">=3.10"
# dependencies = ["pyyaml", "jsonschema>=4.0"]
# ///
"""SKF Validate Brief Schema — schema check for a skill-brief.yaml on disk.

Loads `skill-brief.yaml` from a path (or from stdin/inline-YAML), validates
it against `src/shared/scripts/schemas/skill-brief.v1.json`, and applies the
two conditional rules from `skf-create-skill/references/load-brief.md §3`
that the JSON schema doesn't express today:

  - When `source_type == "docs-only"`: `doc_urls` must have ≥1 entry, and
    `source_authority` must be `community` (the prose says it is "forced
    to community" — we surface a warning when it disagrees rather than
    silently rewriting).
  - `version` must be present AND non-empty AND not whitespace-only. The
    schema rejects empty strings via its semver pattern, but a string that
    only contains whitespace would slip past a naive presence check; we
    catch that case explicitly so the downstream directory-resolution code
    doesn't produce `{name}//` paths.

The script produces skill-friendly error messages — translating raw
jsonschema diagnostics into the "Brief validation failed: ..." form the
calling stage prose already uses. Calling stages can read `errors[]`
directly and forward the `message` field to the user.

CLI:
  uv run skf-validate-brief-schema.py <path/to/skill-brief.yaml>
  cat brief.yaml | uv run skf-validate-brief-schema.py -
  uv run skf-validate-brief-schema.py --yaml '<inline yaml>'

Output (JSON on stdout):
  {
    "valid": bool,
    "errors":   [{"field": "...", "message": "..."}, ...],
    "warnings": [{"field": "...", "message": "..."}, ...],
    "halt_reason": "brief-missing" | "brief-malformed" | "brief-invalid" | null,
    "brief": { ...parsed YAML if loadable, else null... }
  }

Exit codes:
  0 — valid (errors empty)
  1 — invalid (errors non-empty) OR file/yaml load failed
"""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path
from typing import Any

import yaml
from jsonschema import Draft202012Validator


REPO_ROOT = Path(__file__).resolve().parent.parent.parent.parent
SCHEMA_PATH = (
    REPO_ROOT / "src" / "shared" / "scripts" / "schemas" / "skill-brief.v1.json"
)


# --------------------------------------------------------------------------
# Loading
# --------------------------------------------------------------------------


def load_schema() -> dict:
    """Read the skill-brief schema from its canonical path."""
    return json.loads(SCHEMA_PATH.read_text(encoding="utf-8"))


def load_brief_text(text: str) -> tuple[dict | None, str | None]:
    """Parse YAML text. Returns (brief, error_message)."""
    try:
        brief = yaml.safe_load(text)
    except yaml.YAMLError as exc:
        return None, f"Brief is not valid YAML: {exc}"
    if brief is None:
        return None, "Brief is empty"
    if not isinstance(brief, dict):
        return None, f"Brief must be a YAML mapping; got {type(brief).__name__}"
    return brief, None


# --------------------------------------------------------------------------
# Error translation
# --------------------------------------------------------------------------


def _field_path(error_path: tuple) -> str:
    """Render a jsonschema error path as `a.b[0].c`."""
    parts: list[str] = []
    for p in error_path:
        if isinstance(p, int):
            parts.append(f"[{p}]")
        else:
            parts.append(f".{p}" if parts else str(p))
    return "".join(parts) or "(root)"


def _translate_jsonschema_error(err) -> dict:
    """Produce a skill-friendly error record from a jsonschema ValidationError."""
    field = _field_path(err.absolute_path)
    validator = err.validator
    inst = err.instance

    if validator == "required":
        missing = err.message.split("'")[1] if "'" in err.message else "(unknown)"
        return {
            "field": missing,
            "message": (
                f"Brief validation failed: missing required field `{missing}`. "
                f"Update your skill-brief.yaml and re-run."
            ),
        }
    if validator == "pattern":
        return {
            "field": field,
            "message": (
                f"Brief validation failed: `{field}` field `{inst}` does not "
                f"match required pattern `{err.validator_value}`. "
                f"Update your skill-brief.yaml and re-run."
            ),
        }
    if validator == "enum":
        return {
            "field": field,
            "message": (
                f"Brief validation failed: `{field}` field `{inst}` is not one of "
                f"{err.validator_value}. Update your skill-brief.yaml and re-run."
            ),
        }
    if validator == "type":
        expected = err.validator_value
        actual = type(inst).__name__
        return {
            "field": field,
            "message": (
                f"Brief validation failed: `{field}` field has type `{actual}`, "
                f"expected `{expected}`. Update your skill-brief.yaml and re-run."
            ),
        }
    if validator == "minLength":
        return {
            "field": field,
            "message": (
                f"Brief validation failed: `{field}` field must be non-empty. "
                f"Update your skill-brief.yaml and re-run."
            ),
        }
    if validator == "minItems":
        return {
            "field": field,
            "message": (
                f"Brief validation failed: `{field}` field must contain at least "
                f"{err.validator_value} item(s). Update your skill-brief.yaml and re-run."
            ),
        }
    # Fallback — preserve raw message but with consistent prefix
    return {
        "field": field,
        "message": f"Brief validation failed: `{field}` — {err.message}",
    }


# --------------------------------------------------------------------------
# Conditional rules from §3 prose
# --------------------------------------------------------------------------


def _docs_only_rules(brief: dict) -> tuple[list[dict], list[dict]]:
    """Apply the docs-only conditional rules.

    Returns (errors, warnings).
    """
    errors: list[dict] = []
    warnings: list[dict] = []
    if brief.get("source_type") != "docs-only":
        return errors, warnings

    doc_urls = brief.get("doc_urls")
    if not isinstance(doc_urls, list) or len(doc_urls) == 0:
        errors.append(
            {
                "field": "doc_urls",
                "message": (
                    "Brief validation failed: `doc_urls` must have at least one "
                    "entry when `source_type` is `docs-only`. "
                    "Update your skill-brief.yaml and re-run."
                ),
            }
        )

    source_authority = brief.get("source_authority")
    if source_authority not in (None, "community"):
        warnings.append(
            {
                "field": "source_authority",
                "message": (
                    f"`source_authority` is `{source_authority}` but will be treated "
                    f"as `community` because `source_type` is `docs-only`."
                ),
            }
        )
    return errors, warnings


def _version_non_empty_rule(brief: dict) -> list[dict]:
    """The §3 prose calls out version-whitespace-only as a hard error."""
    version = brief.get("version")
    if isinstance(version, str) and version.strip() == "" and version != "":
        # purely whitespace — schema's minLength check on patterns won't catch
        # leading/trailing whitespace that strips to empty
        return [
            {
                "field": "version",
                "message": (
                    "Brief validation failed: `version` field is required and "
                    "must be non-empty. Update your skill-brief.yaml and re-run."
                ),
            }
        ]
    return []


# --------------------------------------------------------------------------
# Main validate
# --------------------------------------------------------------------------


def validate_brief(brief: dict) -> dict:
    """Validate a parsed brief against the schema + conditional rules."""
    schema = load_schema()
    validator = Draft202012Validator(schema)

    errors: list[dict] = []
    warnings: list[dict] = []

    for err in sorted(validator.iter_errors(brief), key=lambda e: e.absolute_path):
        errors.append(_translate_jsonschema_error(err))

    cond_errors, cond_warnings = _docs_only_rules(brief)
    errors.extend(cond_errors)
    warnings.extend(cond_warnings)

    errors.extend(_version_non_empty_rule(brief))

    return {
        "valid": not errors,
        "errors": errors,
        "warnings": warnings,
    }


# --------------------------------------------------------------------------
# CLI
# --------------------------------------------------------------------------


def _emit(envelope: dict) -> None:
    json.dump(envelope, sys.stdout, indent=2)
    sys.stdout.write("\n")


def _envelope_load_error(reason: str, message: str) -> dict:
    return {
        "valid": False,
        "errors": [{"field": "(file)", "message": message}],
        "warnings": [],
        "halt_reason": reason,
        "brief": None,
    }


def _envelope_invalid(brief: dict, errors: list[dict], warnings: list[dict]) -> dict:
    return {
        "valid": False,
        "errors": errors,
        "warnings": warnings,
        "halt_reason": "brief-invalid",
        "brief": brief,
    }


def _envelope_valid(brief: dict, warnings: list[dict]) -> dict:
    return {
        "valid": True,
        "errors": [],
        "warnings": warnings,
        "halt_reason": None,
        "brief": brief,
    }


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        prog="skf-validate-brief-schema",
        description="Validate a skill-brief.yaml against the SKF brief schema.",
    )
    src = parser.add_mutually_exclusive_group(required=True)
    src.add_argument(
        "path",
        nargs="?",
        help="path to skill-brief.yaml; pass `-` to read from stdin",
    )
    src.add_argument(
        "--yaml",
        dest="inline_yaml",
        help="inline YAML text to validate (alternative to a path)",
    )
    args = parser.parse_args(argv)

    if args.inline_yaml is not None:
        text = args.inline_yaml
    elif args.path == "-":
        text = sys.stdin.read()
    else:
        brief_path = Path(args.path)
        if not brief_path.is_file():
            _emit(
                _envelope_load_error(
                    "brief-missing",
                    f"Brief not found at `{brief_path}`. Run [BS] Brief Skill to "
                    "create one, or use [QS] Quick Skill for brief-less generation.",
                )
            )
            return 1
        text = brief_path.read_text(encoding="utf-8")

    brief, load_err = load_brief_text(text)
    if load_err is not None:
        _emit(_envelope_load_error("brief-malformed", load_err))
        return 1
    assert brief is not None

    result = validate_brief(brief)
    if not result["valid"]:
        _emit(_envelope_invalid(brief, result["errors"], result["warnings"]))
        return 1

    _emit(_envelope_valid(brief, result["warnings"]))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Tests for skf-validate-brief-inputs.py.

The validator is pure — it parses a dict and returns a result envelope.
Tests build payloads inline and call validate() directly.
"""

from __future__ import annotations

import importlib.util
import json
import subprocess
import sys
from pathlib import Path

import pytest

SCRIPT_PATH = (
    Path(__file__).parent.parent
    / "src"
    / "shared"
    / "scripts"
    / "skf-validate-brief-inputs.py"
)

spec = importlib.util.spec_from_file_location("skf_validate_brief_inputs", SCRIPT_PATH)
mod = importlib.util.module_from_spec(spec)
spec.loader.exec_module(mod)


# --------------------------------------------------------------------------
# Required fields
# --------------------------------------------------------------------------


class TestRequiredFields:
    def test_both_required_present_minimal_valid(self):
        out = mod.validate({"target_repo": "https://github.com/foo/bar", "skill_name": "foo-bar"})
        assert out["valid"] is True
        assert out["errors"] == []
        assert out["halt_reason"] is None

    def test_missing_target_repo_halts_input_missing(self):
        out = mod.validate({"skill_name": "foo-bar"})
        assert out["valid"] is False
        assert any(e["field"] == "target_repo" for e in out["errors"])
        assert out["halt_reason"] == "input-missing"

    def test_missing_skill_name_halts_input_missing(self):
        out = mod.validate({"target_repo": "https://github.com/foo/bar"})
        assert out["valid"] is False
        assert any(e["field"] == "skill_name" for e in out["errors"])
        assert out["halt_reason"] == "input-missing"

    def test_both_missing_emits_two_errors(self):
        out = mod.validate({})
        assert out["valid"] is False
        fields = {e["field"] for e in out["errors"]}
        assert {"target_repo", "skill_name"}.issubset(fields)

    def test_both_missing_halt_reason_is_input_missing(self):
        out = mod.validate({})
        assert out["halt_reason"] == "input-missing"

    def test_missing_required_plus_invalid_enum_prefers_input_missing(self):
        # target_repo absent + scope_type invalid — "missing" should dominate
        out = mod.validate({"skill_name": "foo", "scope_type": "not-real"})
        assert out["valid"] is False
        assert out["halt_reason"] == "input-missing"


# --------------------------------------------------------------------------
# skill_name format
# --------------------------------------------------------------------------


class TestSkillNameFormat:
    @pytest.mark.parametrize("name", ["foo", "foo-bar", "foo-bar-baz", "foo123", "a", "a1-b2"])
    def test_valid_kebab(self, name):
        out = mod.validate({"target_repo": "/x", "skill_name": name})
        assert out["valid"] is True

    @pytest.mark.parametrize(
        "name",
        ["FooBar", "foo_bar", "Foo-Bar", "-foo", "foo-", "foo bar", "foo.bar", ""],
    )
    def test_invalid_kebab(self, name):
        out = mod.validate({"target_repo": "/x", "skill_name": name})
        if name == "":
            # Empty string falls under "missing" path, not "format" path
            assert out["valid"] is False
            assert any(e["field"] == "skill_name" for e in out["errors"])
        else:
            assert out["valid"] is False
            assert any(
                e["field"] == "skill_name" and "kebab-case" in e["message"]
                for e in out["errors"]
            )


# --------------------------------------------------------------------------
# source_type / source_authority enums
# --------------------------------------------------------------------------


class TestEnums:
    def test_source_type_default_source(self):
        out = mod.validate({"target_repo": "/x", "skill_name": "foo"})
        assert out["normalized"]["source_type"] == "source"

    def test_source_type_invalid(self):
        out = mod.validate(
            {"target_repo": "/x", "skill_name": "foo", "source_type": "weird"}
        )
        assert out["valid"] is False
        assert any(e["field"] == "source_type" for e in out["errors"])
        assert out["halt_reason"] == "input-invalid"

    def test_source_authority_absent_when_not_supplied_for_source(self):
        # source_authority is intentionally left absent so step 1 §3.3's headless
        # detection branch (gh api user vs repo owner) can run.
        out = mod.validate({"target_repo": "/x", "skill_name": "foo"})
        assert "source_authority" not in out["normalized"]

    def test_source_authority_forced_community_for_docs_only_when_absent(self):
        out = mod.validate(
            {
                "target_repo": "/x",
                "skill_name": "foo",
                "source_type": "docs-only",
                "doc_urls": ["https://docs.example.com"],
            }
        )
        assert out["normalized"]["source_authority"] == "community"

    def test_source_authority_invalid(self):
        out = mod.validate(
            {
                "target_repo": "/x",
                "skill_name": "foo",
                "source_authority": "rogue",
            }
        )
        assert out["valid"] is False
        assert any(e["field"] == "source_authority" for e in out["errors"])

    def test_scope_type_when_set_must_be_valid(self):
        out = mod.validate(
            {
                "target_repo": "/x",
                "skill_name": "foo",
                "scope_type": "not-a-real-type",
            }
        )
        assert out["valid"] is False
        assert any(e["field"] == "scope_type" for e in out["errors"])

    @pytest.mark.parametrize(
        "scope_type",
        [
            "full-library",
            "specific-modules",
            "public-api",
            "component-library",
            "reference-app",
            "docs-only",
        ],
    )
    def test_scope_type_all_six_valid(self, scope_type):
        out = mod.validate(
            {"target_repo": "/x", "skill_name": "foo", "scope_type": scope_type}
        )
        assert out["valid"] is True


# --------------------------------------------------------------------------
# target_version semver
# --------------------------------------------------------------------------


class TestTargetVersion:
    @pytest.mark.parametrize(
        "v",
        [
            "1.2.3",
            "1.2.3-rc.1",
            "1.2.3+build.5",
            "1.0.0-alpha+001",
            "v1.2.3",
            "1.2.3.dev1",
            "2024.04.01",  # CalVer — three numeric components
        ],
    )
    def test_valid_semver_forms(self, v):
        out = mod.validate({"target_repo": "/x", "skill_name": "foo", "target_version": v})
        assert out["valid"] is True, f"expected {v!r} to validate; got {out['errors']}"

    @pytest.mark.parametrize(
        "v",
        ["1", "1.2", "v2", "latest", "next", "abc", ".1.2", "1.2.x"],
    )
    def test_invalid_semver_forms(self, v):
        out = mod.validate({"target_repo": "/x", "skill_name": "foo", "target_version": v})
        assert out["valid"] is False, f"expected {v!r} to be rejected"
        assert any(e["field"] == "target_version" for e in out["errors"])

    def test_target_version_must_be_string(self):
        out = mod.validate(
            {"target_repo": "/x", "skill_name": "foo", "target_version": 1.2}
        )
        assert out["valid"] is False
        assert any(e["field"] == "target_version" for e in out["errors"])


# --------------------------------------------------------------------------
# docs-only conditional
# --------------------------------------------------------------------------


class TestDocsOnlyConditional:
    def test_docs_only_without_doc_urls_errors(self):
        out = mod.validate(
            {
                "target_repo": "https://docs.example.com",
                "skill_name": "foo",
                "source_type": "docs-only",
            }
        )
        assert out["valid"] is False
        assert any(e["field"] == "doc_urls" for e in out["errors"])
        assert out["halt_reason"] == "input-missing"

    def test_docs_only_with_doc_urls_valid(self):
        out = mod.validate(
            {
                "target_repo": "https://docs.example.com",
                "skill_name": "foo",
                "source_type": "docs-only",
                "doc_urls": ["https://docs.example.com/api"],
            }
        )
        assert out["valid"] is True

    def test_docs_only_forces_community_authority(self):
        out = mod.validate(
            {
                "target_repo": "https://docs.example.com",
                "skill_name": "foo",
                "source_type": "docs-only",
                "doc_urls": ["https://docs.example.com/api"],
                "source_authority": "official",
            }
        )
        assert out["valid"] is True
        assert out["normalized"]["source_authority"] == "community"
        assert any(
            w["field"] == "source_authority" and "forced" in w["message"]
            for w in out["warnings"]
        )


# --------------------------------------------------------------------------
# target_repo shape (warning, not error)
# --------------------------------------------------------------------------


class TestTargetRepoShape:
    @pytest.mark.parametrize(
        "tr",
        [
            "https://github.com/foo/bar",
            "http://example.com",
            "/abs/path/to/repo",
            "./relative/path",
            "~/home/path",
        ],
    )
    def test_recognized_shapes_no_warning(self, tr):
        out = mod.validate({"target_repo": tr, "skill_name": "foo"})
        assert out["valid"] is True
        assert not any(w["field"] == "target_repo" for w in out["warnings"])

    def test_garbage_target_repo_warns_but_passes(self):
        out = mod.validate({"target_repo": "blarg", "skill_name": "foo"})
        # Still valid (HEAD-check is the workflow's job, not the validator's)
        assert out["valid"] is True
        assert any(w["field"] == "target_repo" for w in out["warnings"])


# --------------------------------------------------------------------------
# Defaults applied to normalized output
# --------------------------------------------------------------------------


class TestNormalization:
    def test_defaults_applied(self):
        out = mod.validate({"target_repo": "/x", "skill_name": "foo"})
        n = out["normalized"]
        assert n["source_type"] == "source"
        # source_authority is NOT defaulted here — see test_source_authority_absent_when_not_supplied_for_source
        assert "source_authority" not in n
        assert n["scripts_intent"] == "detect"
        assert n["assets_intent"] == "detect"

    def test_supplied_values_override_defaults(self):
        out = mod.validate(
            {
                "target_repo": "/x",
                "skill_name": "foo",
                "scripts_intent": "none",
                "assets_intent": "templates only",
            }
        )
        n = out["normalized"]
        assert n["scripts_intent"] == "none"
        assert n["assets_intent"] == "templates only"


# --------------------------------------------------------------------------
# Unknown fields
# --------------------------------------------------------------------------


class TestUnknownFields:
    def test_unknown_field_warns_but_passes(self):
        out = mod.validate(
            {
                "target_repo": "/x",
                "skill_name": "foo",
                "totally_unknown_arg": "value",
            }
        )
        assert out["valid"] is True
        assert any(
            w["field"] == "totally_unknown_arg" for w in out["warnings"]
        )


# --------------------------------------------------------------------------
# CLI integration (subprocess)
# --------------------------------------------------------------------------


class TestCLI:
    def _run(self, payload: dict, via_stdin: bool = False) -> tuple[int, dict]:
        if via_stdin:
            proc = subprocess.run(
                [sys.executable, str(SCRIPT_PATH)],
                input=json.dumps(payload),
                capture_output=True,
                text=True,
            )
        else:
            proc = subprocess.run(
                [sys.executable, str(SCRIPT_PATH), "--json", json.dumps(payload)],
                capture_output=True,
                text=True,
            )
        out = json.loads(proc.stdout) if proc.stdout.strip() else {}
        return proc.returncode, out

    def test_cli_exits_0_on_valid(self):
        code, out = self._run({"target_repo": "/x", "skill_name": "foo"})
        assert code == 0
        assert out["valid"] is True

    def test_cli_exits_1_on_invalid(self):
        code, out = self._run({"skill_name": "foo"})
        assert code == 1
        assert out["valid"] is False
        assert out["halt_reason"] == "input-missing"

    def test_cli_exits_2_on_bad_json(self):
        proc = subprocess.run(
            [sys.executable, str(SCRIPT_PATH), "--json", "not-json"],
            capture_output=True,
            text=True,
        )
        assert proc.returncode == 2
        assert "invalid JSON" in proc.stderr

    def test_cli_accepts_stdin(self):
        code, out = self._run(
            {"target_repo": "/x", "skill_name": "foo"}, via_stdin=True
        )
        assert code == 0
        assert out["valid"] is True

